if (! function_exists('text_reading_time')) {
    function text_reading_time($text, $words_per_minute = null, $include_syllable_time = null)
    {
        $text = (string)$text;
        if (empty(trim($text))) {
            return json_encode(['error' => 'Text is required', 'reading_time_seconds' => 0]);
        }
        $wpm = isset($words_per_minute) && $words_per_minute > 0 ? (int)$words_per_minute : 238;
        $includeSyllable = isset($include_syllable_time) ? (bool)$include_syllable_time : false;

        $wordCount = str_word_count($text, 0, 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789');
        if ($wordCount === 0) {
            $wordCount = count(preg_split('/\s+/', trim($text)));
            if ($wordCount === 0) {
                return json_encode(['error' => 'No words found', 'reading_time_seconds' => 0]);
