        }

        $charCount = mb_strlen($text);
        $charCountNoSpaces = mb_strlen(preg_replace('/\s+/', '', $text));

        $minutes = $wordCount / $wpm;
        $seconds = $minutes * 60;
        $totalSeconds = round($seconds);
        $totalMinutes = floor($minutes);
        $remainingSeconds = round(($minutes - $totalMinutes) * 60);

        $speeds = [
            'slow (audiobook)' => 150,
            'average (adult)' => 238,
            'fast (skimmer)' => 300,
            'very fast (speed reader)' => 450,
        ];

